div.script:
(function(){
    var LOW=55,HIGH=80;
    var prop=document.getElementById('c-prop'),mw=document.getElementById('c-manual-wrap'),
        man=document.getElementById('c-manual'),fin=document.getElementById('c-finish'),
        acc=document.getElementById('c-access'),fig=document.getElementById('c-figure'),note=document.getElementById('c-note');
    if(!prop)return;
    function gbp(n){return '£'+(Math.round(n/50)*50).toLocaleString();}
    function rc(){
      var area=prop.value==='0'?(parseFloat(man.value)||0):parseFloat(prop.value);
      mw.hidden=prop.value!=='0';
      var m=parseFloat(fin.value)*parseFloat(acc.value);
      if(!area){fig.textContent='—';note.textContent='Enter a wall area';return;}
      fig.textContent=gbp(area*LOW*m)+' – '+gbp(area*HIGH*m);
      note.textContent='~'+area+' m² · incl. scaffold, mesh, base & topcoat';
    }
    [prop,man,fin,acc].forEach(function(el){if(el){el.addEventListener('input',rc);el.addEventListener('change',rc);}});
    rc();
  })();

body.script:
document.querySelectorAll('.faq-q').forEach(b=>b.addEventListener('click',function(){
  const open=this.getAttribute('aria-expanded')==='true';
  document.querySelectorAll('.faq-q').forEach(x=>{x.setAttribute('aria-expanded','false');const a=x.nextElementSibling;if(a)a.style.maxHeight=null;const i=x.querySelector('.faq-icon');if(i)i.textContent='+';});
  if(!open){this.setAttribute('aria-expanded','true');const a=this.nextElementSibling;if(a)a.style.maxHeight=a.scrollHeight+'px';const i=this.querySelector('.faq-icon');if(i)i.textContent='×';}
}));
window.ihSubmit=function(f){const c=f.closest('.ihform-wrap');const fm=c.querySelector('.ihform');const ok=c.querySelector('.ihok');const ph=fm.querySelector('[data-req]');if(ph&&!ph.value.trim()){alert('Please enter your phone number.');return;}fm.style.display='none';ok.style.display='block';};
const mn=document.getElementById('mainNav');if(mn){addEventListener('scroll',()=>mn.classList.toggle('scrolled',scrollY>40),{passive:true});}
